import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class ArrayAnnotationRuleTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given an array annotation and the annotated construct is on the same line, then violation is triggered`() {
        val code = """
            @[JvmStatic Provides] fun foo() = 42
        """.trimIndent()
        val formattedCode = """
            @[JvmStatic Provides]
            fun foo() = 42
        """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolation(1, 1, "Array annotation (@[…]) must be placed on a separate line prior to the annotated construct")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an array annotation already on a separate line then no violation occurs`() {
        val code = """
            @[JvmStatic Provides]
            fun foo() = 42
        """.trimIndent()
        annotationRuleAssertThat(code)
            .hasNoLintViolations()
    }
}
